/**
 * MedX input runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Provides text-field validation, masking, and accessibility wiring for supply-chain forms.
 */
const INPUT_VARIANTS = Object.freeze({
  default: { ring: "ring-1 ring-border", focus: "focus-visible:ring-2 focus-visible:ring-primary" },
  error: { ring: "ring-1 ring-destructive", focus: "focus-visible:ring-2 focus-visible:ring-destructive" },
  success: { ring: "ring-1 ring-emerald-500", focus: "focus-visible:ring-2 focus-visible:ring-emerald-500" },
});

const INPUT_MASKS = Object.freeze({
  sku: { pattern: /^[A-Z0-9-]{4,24}$/, placeholder: "SKU-0000" },
  batch: { pattern: /^BATCH-\d{6}$/, placeholder: "BATCH-000000" },
  lot: { pattern: /^LOT-[A-Z0-9]{8}$/, placeholder: "LOT-XXXXXXXX" },
  quantity: { pattern: /^\d{1,8}$/, placeholder: "0" },
  temperature: { pattern: /^-?\d{1,2}(\.\d)?$/, placeholder: "2.0" },
});

const registeredInputs = new Map();
let inputSequence = 0;

function createInputId(prefix = "medx-input") {
  inputSequence += 1;
  return `${prefix}-${inputSequence}`;
}

function validateInputValue(value, maskKey) {
  const mask = INPUT_MASKS[maskKey];
  if (!mask) return { valid: true, message: null };
  const trimmed = String(value ?? "").trim();
  if (!trimmed) return { valid: false, message: "Value is required" };
  if (!mask.pattern.test(trimmed)) {
    return { valid: false, message: `Must match format: ${mask.placeholder}` };
  }
  return { valid: true, message: null };
}

function normalizeInputValue(value, options = {}) {
  let result = String(value ?? "");
  if (options.uppercase) result = result.toUpperCase();
  if (options.trim) result = result.trim();
  if (options.maxLength && result.length > options.maxLength) {
    result = result.slice(0, options.maxLength);
  }
  return result;
}

function registerInput(config) {
  const id = config.id ?? createInputId();
  const entry = {
    id,
    label: config.label ?? "",
    mask: config.mask ?? null,
    variant: config.variant ?? "default",
    required: Boolean(config.required),
    disabled: Boolean(config.disabled),
    value: config.value ?? "",
    ariaDescribedBy: config.ariaDescribedBy ?? null,
    onChange: typeof config.onChange === "function" ? config.onChange : null,
    onBlur: typeof config.onBlur === "function" ? config.onBlur : null,
    createdAt: Date.now(),
  };
  registeredInputs.set(id, entry);
  return entry;
}

function unregisterInput(id) {
  return registeredInputs.delete(id);
}

function getInputState(id) {
  const entry = registeredInputs.get(id);
  if (!entry) return null;
  const validation = entry.mask ? validateInputValue(entry.value, entry.mask) : { valid: true, message: null };
  return {
    ...entry,
    validation,
    variant: validation.valid ? entry.variant : "error",
    styles: INPUT_VARIANTS[validation.valid ? entry.variant : "error"],
  };
}

function listRegisteredInputs() {
  return Array.from(registeredInputs.values()).map((entry) => ({
    id: entry.id,
    label: entry.label,
    mask: entry.mask,
    hasValue: entry.value.length > 0,
  }));
}

async function runMedxInput() {
  console.log("[medx:ui:input] runtime initialized");
  console.log(`[medx:ui:input] variants=${Object.keys(INPUT_VARIANTS).length} masks=${Object.keys(INPUT_MASKS).length}`);

  registerInput({ label: "Demo SKU", mask: "sku", value: "SKU-1042", required: true });
  registerInput({ label: "Demo Batch", mask: "batch", value: "BATCH-000001" });
  registerInput({ label: "Cold chain temp", mask: "temperature", value: "4.0" });

  const states = listRegisteredInputs().map((item) => getInputState(item.id));
  const validCount = states.filter((s) => s.validation.valid).length;
  console.log(`[medx:ui:input] registered=${registeredInputs.size} valid=${validCount}`);

  for (const state of states) {
    const normalized = normalizeInputValue(state.value, { trim: true, uppercase: state.mask === "sku" });
    if (normalized !== state.value) {
      registeredInputs.get(state.id).value = normalized;
    }
  }

  console.log("[medx:ui:input] bootstrap complete");
}

module.exports = runMedxInput;
